code = """import json
import re
import pandas as pd

# Load data
with open(locals()['var_function-call-11580932212010128942'], 'r') as f:
    books_data = json.load(f)

with open(locals()['var_function-call-17321297221859499414'], 'r') as f:
    reviews_data = json.load(f)

# Process books
books_list = []
month_pattern = r'(?:January|February|March|April|May|June|July|August|September|October|November|December)'
date_pattern = re.compile(rf'({month_pattern})\s+\d{{1,2}},?\s+(\d{{4}})')
month_year_pattern = re.compile(rf'({month_pattern})\s+(\d{{4}})')

for book in books_data:
    b_id_str = book['book_id']
    details = book['details']
    
    try:
        b_id = int(b_id_str.split('_')[1])
    except:
        continue
        
    year = None
    match = date_pattern.search(details)
    if match:
        year = int(match.group(2))
    else:
        match_my = month_year_pattern.search(details)
        if match_my:
            year = int(match_my.group(2))
    
    if year:
        books_list.append({'id': b_id, 'year': year})

books_df = pd.DataFrame(books_list)

# Process reviews
reviews_list = []
for review in reviews_data:
    p_id_str = review['purchase_id']
    rating_str = review['rating']
    
    try:
        p_id = int(p_id_str.split('_')[1])
    except:
        continue
        
    try:
        rating = float(rating_str)
    except:
        continue
        
    reviews_list.append({'id': p_id, 'rating': rating})

reviews_df = pd.DataFrame(reviews_list)

merged_df = pd.merge(reviews_df, books_df, on='id', how='inner')
merged_df['decade'] = (merged_df['year'] // 10) * 10
merged_df['decade_str'] = merged_df['decade'].astype(str) + 's'

# Method A: Global average of ratings
stats_global = merged_df.groupby('decade_str').agg(
    distinct_books=('id', 'nunique'),
    avg_rating_global=('rating', 'mean')
).reset_index()

# Method B: Average of book averages
book_stats = merged_df.groupby(['decade_str', 'id']).agg(
    book_avg=('rating', 'mean')
).reset_index()

stats_book_avg = book_stats.groupby('decade_str').agg(
    avg_rating_books=('book_avg', 'mean')
).reset_index()

final_stats = pd.merge(stats_global, stats_book_avg, on='decade_str')

print("__RESULT__:")
print(json.dumps(final_stats.to_dict(orient='records')))"""

